const body = $('POST /review/analyze').first().json.body || $('POST /review/analyze').first().json;
const startTime = Date.now();

let text = body.text || '';
const prefixes = ['analyze this review:', 'review this:', 'analyze:', 'review:'];
for (const p of prefixes) {
  if (text.toLowerCase().startsWith(p)) {
    text = text.substring(p.length).trim();
    break;
  }
}

return [{
  json: {
    text: text,
    review_type: body.type || 'restaurant',
    source: body.source || 'frontend',
    start_time: startTime
  }
}];

const response = $json;
const content = response.message?.content || response.response || '';
const reviewText = $('Prepare Request').first().json.text;
const reviewType = $('Prepare Request').first().json.review_type;

try {
  let jsonStr = content.trim();
  const codeBlockMatch = jsonStr.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (codeBlockMatch) {
    jsonStr = codeBlockMatch[1].trim();
  } else {
    const jsonMatch = jsonStr.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      jsonStr = jsonMatch[0];
    } else {
      // No closing brace found — model likely truncated. Try adding one.
      const openBrace = jsonStr.indexOf('{');
      if (openBrace >= 0) {
        jsonStr = jsonStr.substring(openBrace);
        // Count braces to fix truncation
        let open = 0;
        for (const ch of jsonStr) {
          if (ch === '{') open++;
          if (ch === '}') open--;
        }
        while (open > 0) { jsonStr += '}'; open--; }
      }
    }
  }

  // Also fix truncated JSON even when regex matched — verify brace balance
  let openBraces = 0;
  for (const ch of jsonStr) {
    if (ch === '{') openBraces++;
    if (ch === '}') openBraces--;
  }
  while (openBraces > 0) { jsonStr += '}'; openBraces--; }

  const parsed = JSON.parse(jsonStr);

  const validSentiments = ['positive', 'negative', 'mixed'];
  const result = {
    sentiment: validSentiments.includes(parsed.sentiment) ? parsed.sentiment : 'mixed',
    sentiment_score: Math.max(0, Math.min(1, parseFloat(parsed.sentiment_score) || 0.5)),
    key_themes: Array.isArray(parsed.key_themes) ? parsed.key_themes.map(String).slice(0, 10) : [],
    pros: Array.isArray(parsed.pros) ? parsed.pros.map(String).slice(0, 10) : [],
    cons: Array.isArray(parsed.cons) ? parsed.cons.map(String).slice(0, 10) : [],
    predicted_rating: Math.max(1, Math.min(5, Math.round(parseFloat(parsed.predicted_rating)) || 3)),
    summary: typeof parsed.summary === 'string' && parsed.summary.length > 0 ? parsed.summary : 'No summary available.',
    _raw_text: reviewText,
    _review_type: reviewType,
    _analyzed_at: new Date().toISOString(),
    _parse_success: true
  };

  return [{ json: result }];
} catch (e) {
  return [{
    json: {
      _parse_success: false,
      _error: 'Failed to parse AI response: ' + e.message,
      _raw_response: content,
      sentiment: 'mixed',
      sentiment_score: 0.5,
      key_themes: [],
      pros: [],
      cons: [],
      predicted_rating: 3,
      summary: 'Analysis could not be completed. The AI response was malformed.'
    }
  }];
}

